import express, { type Request, type Response, type NextFunction } from "express";
import cors from "cors";
import { config } from "./config.js";
import { buildRoutes, errorHandler } from "./routes/index.js";

function bearerGuard() {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!config.bearerToken) return next();
    const header = req.header("authorization") ?? "";
    const expected = `Bearer ${config.bearerToken}`;
    if (header !== expected) {
      res.status(401).json({ error: "UNAUTHORIZED" });
      return;
    }
    next();
  };
}

function main() {
  const app = express();
  app.use(cors());
  app.use(express.json({ limit: "1mb" }));
  app.use(bearerGuard());
  app.use("/", buildRoutes());
  app.use(errorHandler);

  app.listen(config.port, () => {
    console.log(`open-seo-api listening on http://localhost:${config.port}`);
    if (!config.dataforseoApiKey) {
      console.warn("[warn] DATAFORSEO_API_KEY is not set — DataForSEO-backed endpoints will 500.");
    }
  });
}

main();

